def _generate_day(sign_slug: str) -> str:
    today = date.today().isoformat()
    idx = int(hashlib.md5(f"{today}{sign_slug}".encode()).hexdigest(), 16) % 7
    sign_ru = SIGN_RU.get(sign_slug, sign_slug)
    phrases = _DAY_BY_SIGN.get(sign_slug, [])
    text = phrases[idx] if phrases else "Сегодня звёзды благоволят вашим начинаниям."
    return f"Гороскоп на сегодня для знака {sign_ru}\n\n{text}"


def _generate_week(sign_slug: str) -> str:
    today = date.today()
    week_num = today.isocalendar()[1]
    idx = int(hashlib.md5(f"{today.year}{week_num}{sign_slug}".encode()).hexdigest(), 16) % 4
    sign_ru = SIGN_RU.get(sign_slug, sign_slug)
    phrases = _WEEK_BY_SIGN.get(sign_slug, [])
    text = phrases[idx] if phrases else "Эта неделя насыщена событиями."
    return f"Гороскоп на неделю для знака {sign_ru}\n\n{text}"


def get_daily_horoscope(sign_slug: str) -> str:
    url = f"{BASE_URL}/goroskop-na-segodnya-{sign_slug}"
    text = _fetch(url, ttl=3600)
    return text if text else _generate_day(sign_slug)


def get_weekly_horoscope(sign_slug: str) -> str:
    url = f"{BASE_URL}/goroskop-na-nedelyu-{sign_slug}"
    text = _fetch(url, ttl=6 * 3600)
    return text if text else _generate_week(sign_slug)
